module RefModule (
	input clk,
	input rst,
	input load,
	input [15:0] load_val,
	output reg [15:0] q,
	output tc);

	always @(posedge clk or posedge rst) begin
		if (rst)
			q <= 16'b0000000000000000;
		else if (load)
			q <= load_val;
		else
			q <= {q[14:0], 1'b0};
	end

	wire __tc_tmp = q[15];
	assign tc = __tc_tmp;

endmodule
